  if (!data.events && !data.leagues) {
    return { message: 'No scores data available.', action: 'scores', games: [] };
  }

  let events = data.events || [];

  // Filter by team if provided
  if (teamQuery && sport !== 'f1') {
    events = events.filter(e => {
      const competitors = e.competitions?.[0]?.competitors || [];
      return competitors.some(c => {
        const abbr = (c.team?.abbreviation || '').toLowerCase();
        const name = (c.team?.displayName || '').toLowerCase();
        const id = c.team?.id || '';
        return abbr === teamId || name.includes(teamQuery) || id === teamId;
      });
    });
  }

  let games = [];
  let lines = [];

  switch (sport) {
    case 'f1': {
      // Find most recent completed race
      const completedEvents = events.filter(e => {
        const status = e.competitions?.[0]?.status?.type?.completed;
        return status === true;
      });
      if (completedEvents.length === 0) {
        return { message: 'No completed F1 races found yet this season.', action: 'scores', games: [] };
      }
      const lastRace = completedEvents[completedEvents.length - 1];
      const raceName = lastRace.name || 'Race';
      const competitors = lastRace.competitions?.[0]?.competitors || [];
      const sorted = competitors.sort((a, b) => (parseInt(a.order) || 99) - (parseInt(b.order) || 99));
      const podium = sorted.slice(0, 3);

      if (podium.length >= 3) {
        const winner = podium[0].athlete?.displayName || podium[0].team?.displayName || 'Unknown';
        const second = podium[1].athlete?.displayName || podium[1].team?.displayName || 'Unknown';
        const third = podium[2].athlete?.displayName || podium[2].team?.displayName || 'Unknown';
        lines.push(`${winner} won the ${raceName}. ${second} second, ${third} third.`);
      } else if (podium.length > 0) {
        const winner = podium[0].athlete?.displayName || podium[0].team?.displayName || 'Unknown';
        lines.push(`${winner} won the ${raceName}.`);
      }

      // Filter by driver if provided
      let driverQuery = params.driverQuery;
      if (driverQuery) {
        const driverResult = sorted.find(c => {
          const name = (c.athlete?.displayName || c.team?.displayName || '').toLowerCase();
          return name.includes(driverQuery);
        });
        if (driverResult) {
          const pos = driverResult.order || '?';
          const dName = driverResult.athlete?.displayName || driverResult.team?.displayName;
          lines.push(`${dName} finished P${pos}.`);
        }
      }

      games = podium.map(c => ({
        position: c.order,
        driver: c.athlete?.displayName || c.team?.displayName,
        team: c.team?.displayName
      }));
      break;
