  let games = [];
  let lines = [];

  if (sport === 'f1') {
    // F1 uses scoreboard data for schedule
    const events = data.events || [];
    const now = new Date();
    const upcoming = events.filter(e => new Date(e.date) > now);

    if (upcoming.length === 0) {
      return { message: 'No upcoming F1 races found.', action: 'schedule', games: [] };
    }

    const next = upcoming.slice(0, 3);
    next.forEach((e, i) => {
      const name = e.name || 'Race';
      const dateStr = new Date(e.date).toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' });
      if (i === 0) {
        lines.push(`The next F1 race is the ${name} on ${dateStr}.`);
      } else {
        lines.push(`${name} on ${dateStr}.`);
      }
      games.push({ race: name, date: e.date });
    });

    return { message: lines.join(' '), action: 'schedule', games };
  }

  // Team sports schedule
  const scheduleEvents = data.events || [];
  const now = new Date();
  const upcoming = scheduleEvents.filter(e => new Date(e.date) > now);

  if (upcoming.length === 0) {
    return { message: 'No upcoming games found.', action: 'schedule', games: [] };
  }

  const next = upcoming.slice(0, 3);

  next.forEach(e => {
    const comp = e.competitions?.[0];
    const competitors = comp?.competitors || [];
    const dateStr = new Date(e.date).toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' });

    if (sport === 'epl' || sport === 'mls') {
      // Soccer: parse from competitors, find opponent by team ID mismatch
      const ourTeam = competitors.find(c => c.team?.id === teamId);
      const opponent = competitors.find(c => c.team?.id !== teamId);
      if (ourTeam && opponent) {
        const oppName = opponent.team?.displayName || opponent.team?.name || 'Unknown';
        const location = ourTeam.homeAway === 'home' ? 'vs' : 'at';
        lines.push(`${location === 'vs' ? 'vs' : 'at'} ${oppName} - ${dateStr}.`);
      } else {
        // Fallback
        const shortName = e.shortName || e.name || '';
        lines.push(`${shortName} - ${dateStr}.`);
      }
      games.push({
        opponent: competitors.find(c => c.team?.id !== teamId)?.team?.displayName,
        date: e.date,
        homeAway: competitors.find(c => c.team?.id === teamId)?.homeAway
      });
    } else {
      // NBA/NFL/NHL: parse shortName (format "ABBR @ ABBR")
      const shortName = e.shortName || '';
      const parts = shortName.split(/\s*[@]\s*/);
      if (parts.length === 2) {
        const awayAbbr = parts[0].trim();
        const homeAbbr = parts[1].trim();
        const awayName = abbrevToName[awayAbbr] || awayAbbr;
        const homeName = abbrevToName[homeAbbr] || homeAbbr;
        const upperTeamId = teamId.toUpperCase();

        if (awayAbbr === upperTeamId) {
          lines.push(`at ${homeName} - ${dateStr}.`);
        } else if (homeAbbr === upperTeamId) {
          lines.push(`vs ${awayName} - ${dateStr}.`);
        } else {
          lines.push(`${awayName} at ${homeName} - ${dateStr}.`);
        }

        games.push({
          away: awayName, home: homeName, date: e.date,
          homeAway: awayAbbr === upperTeamId ? 'away' : 'home'
        });
      } else {
        lines.push(`${shortName || e.name} - ${dateStr}.`);
        games.push({ name: shortName || e.name, date: e.date });
      }
    }
  });

  const sportLabels = { nba: 'NBA', nfl: 'NFL', nhl: 'NHL', epl: 'EPL', mls: 'MLS' };
  const label = sportLabels[sport];
  const message = `Upcoming ${label} schedule: ` + lines.join(' ');

  return { message, action: 'schedule', games };
} catch (error) {
  return { message: 'Error processing schedule: ' + error.message, action: 'schedule', games: [] };
}

